import {
  Component,
  Element,
  Prop,
  Event,
  EventEmitter,
  h
} from '@stencil/core';
import {
  determineMessageDismissalButtonVariant,
  dismissalButtonInMessageShouldBeInverse
} from '@src/utils/kds-utils/colorUtils';
import { iconPaletteMap } from '@src/utils/kds-utils/iconUtils';

const ToastConversionMap: Record<string, any> = {
  success: { kind: 'subtle', palette: 'positive', variant: 'fill', icon: 'success' },
  warning:
    { kind: 'subtle', palette: 'callout', variant: 'fill', icon: 'warning' },
  error:
    { kind: 'subtle', palette: 'negative', variant: 'fill', icon: 'error' },
  info: { kind: 'subtle', palette: 'informative', variant: 'fill', icon: 'info' }
};

/**
 * A toast is used to display feedback to the user based on an action.
 */

@Component({
  tag: 'kds-toast',
  shadow: false
})
export class KdsToast {
  @Element() hostEl: HTMLKdsToastElement;

  /** Sets the color palette. */
  // prettier-ignore
  @Prop({ mutable: true }) palette: 'neutral' | 'brand' | 'accent' | 'positive' | 'negative' | 'informative' | 'callout' | 'special' = 'accent';
  /** Sets the color kind. */
  @Prop({ mutable: true }) kind: 'success' | 'info' | 'warning' | 'error' | 'dominant' | 'prominent' | 'subtle' | 'alternate' = 'subtle';
  /** Sets the color variant. */
  @Prop({ mutable: true }) variant: 'fill' | 'border' = 'fill';
  /** Applies the inverse color styling. */
  @Prop() readonly inverse: boolean = false;
  /** Determines which icon to display. */
  // prettier-ignore
  @Prop({ mutable: true }) icon?: 'success' | 'info' | 'warning' | 'recall' | 'error' | 'failure';
  /** Heading text. */
  @Prop() readonly heading!: string;
  /** The message text.
   * Use this prop **or** provide your message as a child to the component. See [Examples](#Examples) */
  @Prop() readonly message?: string;
  /** Optional value for explicitly setting the timeout for closing the Toast; in milliseconds */
  @Prop() readonly customTimeout?: number;

  /** Fires when the message is closed by the user. */
  @Event() toastClose: EventEmitter;

  /** Emits when the component is loaded. */
  @Event() ready: EventEmitter;

  handleClose() {
    this.toastClose.emit();
  }

  componentWillLoad() {
    if (ToastConversionMap[this.kind]) {
      this.palette = ToastConversionMap[this.kind].palette;
      this.variant = ToastConversionMap[this.kind].variant;
      this.kind = ToastConversionMap[this.kind].kind;
      this.icon = ToastConversionMap[this.kind].icon;
    }
  }

  componentDidLoad() {
    this.ready.emit();
  }

  render() {
    const { heading, icon, inverse, kind, message, palette, variant, hostEl } =
      this;
    const iconName = icon || iconPaletteMap[palette] || 'info';
    const ToastIcon: string = `kds-icon-${iconName}`;
    const sectionClasses = {
      'kds-Toast': true,
      [`palette-${palette}`]: true,
      [`kind-${kind}`]: true,
      [`variant-${variant}`]: true,
      'as-inverse': inverse
    };
    const dismissalButtonClasses = {
      [`palette-${palette}`]: true,
      [`kind-${kind}`]: true,
      [`variant-${determineMessageDismissalButtonVariant({
        messageInverseState: inverse,
        messageKind: kind,
        messageVariant: variant
      })}`]: true,
      interactive: true,
      'as-inverse': dismissalButtonInMessageShouldBeInverse({
        messageInverseState: inverse,
        messageKind: kind,
        messageVariant: variant
      }),
      'kds-DismissalButton': true,
      'kds-Toast-closeButton': true
    };

    return (
      <section
        role='alert'
        aria-live='assertive'
        aria-label={`${iconName} message: ${heading ? heading : ''} ${(
          message || hostEl.textContent
        )?.trim()}`}
        class={{
          ...sectionClasses
        }}
      >
        <header class='kds-Toast-header'>
          <ToastIcon size='utility-l' class='kds-Toast-icon' />
          <h1 class='kds-Toast-heading'>{heading}</h1>
        </header>
        <p class='kds-Toast-body'>
          <slot />
          {message}
        </p>
        <button
          aria-label='Close alert'
          onClick={() => this.handleClose()}
          class={{
            ...dismissalButtonClasses
          }}
        >
          <kds-icon-close size='xs' />
        </button>
      </section>
    );
  }
}
